			`  cat "${rewindFile}"`,
			"  exit 0",
			"fi",
			"if [ \"$1\" = \"explain\" ]; then",
			"  case \" $* \" in",
			"    *\" --full \"*)",
			`      cat "${explainFullFile}"`,
			"      exit 0",
			"      ;;",
			"    *)",
			`      cat "${explainFile}"`,
